2225 // Compute the ordering we will process the inputs: the rough heuristic here
2226 // is to sort them per size so that the largest module get schedule as soon as
2227 // possible. This is purely a compile-time optimization.
2228 std::vector<int> lto::generateModulesOrdering(ArrayRef<BitcodeModule *> R) {
2229   auto Seq = llvm::seq<int>(0, R.size());
