2231   llvm::sort(ModulesOrdering, [&](int LeftIndex, int RightIndex) {
2232     auto LSize = R[LeftIndex]->getBuffer().size();
2233     auto RSize = R[RightIndex]->getBuffer().size();
2234     return LSize > RSize;
2235   });
2236   return ModulesOrdering;
