369 static void thinLTOResolvePrevailingGUID(
370     const Config &C, ValueInfo VI,
371     DenseSet<GlobalValueSummary *> &GlobalInvolvedWithAlias,
372     function_ref<bool(GlobalValue::GUID, const GlobalValueSummary *)>
373         isPrevailing,
374     function_ref<void(StringRef, GlobalValue::GUID, GlobalValue::LinkageTypes)>
375         recordNewLinkage,
376     const DenseSet<GlobalValue::GUID> &GUIDPreservedSymbols) {
377   GlobalValue::VisibilityTypes Visibility =
378       C.VisibilityScheme == Config::ELF ? VI.getELFVisibility()
379                                         : GlobalValue::DefaultVisibility;
380   for (auto &S : VI.getSummaryList()) {
381     GlobalValue::LinkageTypes OriginalLinkage = S->linkage();
382     // Ignore local and appending linkage values since the linker
383     // doesn't resolve them.
384     if (GlobalValue::isLocalLinkage(OriginalLinkage) ||
385         GlobalValue::isAppendingLinkage(S->linkage()))
386       continue;
387     // We need to emit only one of these. The prevailing module will keep it,
388     // but turned into a weak, while the others will drop it when possible.
389     // This is both a compile-time optimization and a correctness
390     // transformation. This is necessary for correctness when we have exported
391     // a reference - we need to convert the linkonce to weak to
392     // ensure a copy is kept to satisfy the exported reference.
393     // FIXME: We may want to split the compile time and correctness
394     // aspects into separate routines.
395     if (isPrevailing(VI.getGUID(), S.get())) {
396       assert(!S->wasPromoted() &&
397              "promoted symbols used to be internal linkage and shouldn't have "
398              "a prevailing variant");
399       if (GlobalValue::isLinkOnceLinkage(OriginalLinkage)) {
400         S->setLinkage(GlobalValue::getWeakLinkage(
401             GlobalValue::isLinkOnceODRLinkage(OriginalLinkage)));
402         // The kept copy is eligible for auto-hiding (hidden visibility) if all
403         // copies were (i.e. they were all linkonce_odr global unnamed addr).
404         // If any copy is not (e.g. it was originally weak_odr), then the symbol
405         // must remain externally available (e.g. a weak_odr from an explicitly
406         // instantiated template). Additionally, if it is in the
407         // GUIDPreservedSymbols set, that means that it is visibile outside
408         // the summary (e.g. in a native object or a bitcode file without
409         // summary), and in that case we cannot hide it as it isn't possible to
410         // check all copies.
411         S->setCanAutoHide(VI.canAutoHide() &&
412                           !GUIDPreservedSymbols.count(VI.getGUID()));
413       }
414       if (C.VisibilityScheme == Config::FromPrevailing)
415         Visibility = S->getVisibility();
416     }
417     // Alias and aliasee can't be turned into available_externally.
418     // When force-import-all is used, it indicates that object linking is not
419     // supported by the target. In this case, we can't change the linkage as
420     // well in case the global is converted to declaration.
421     // Also, if the symbol was promoted, it wouldn't have a prevailing variant,
422     // but also its linkage is set correctly (to External) already.
423     else if (!isa<AliasSummary>(S.get()) &&
424              !GlobalInvolvedWithAlias.count(S.get()) && !ForceImportAll &&
425              !S->wasPromoted())
426       S->setLinkage(GlobalValue::AvailableExternallyLinkage);
427 
428     // For ELF, set visibility to the computed visibility from summaries. We
429     // don't track visibility from declarations so this may be more relaxed than
430     // the most constraining one.
431     if (C.VisibilityScheme == Config::ELF)
432       S->setVisibility(Visibility);
433 
434     if (S->linkage() != OriginalLinkage)
435       recordNewLinkage(S->modulePath(), VI.getGUID(), S->linkage());
436   }
437 
438   if (C.VisibilityScheme == Config::FromPrevailing) {
439     for (auto &S : VI.getSummaryList()) {
440       GlobalValue::LinkageTypes OriginalLinkage = S->linkage();
441       if (GlobalValue::isLocalLinkage(OriginalLinkage) ||
442           GlobalValue::isAppendingLinkage(S->linkage()))
443         continue;
444       S->setVisibility(Visibility);
445     }
446   }
447 }
