449 /// Resolve linkage for prevailing symbols in the \p Index.
450 //
451 // We'd like to drop these functions if they are no longer referenced in the
452 // current module. However there is a chance that another module is still
453 // referencing them because of the import. We make sure we always emit at least
454 // one copy.
455 void llvm::thinLTOResolvePrevailingInIndex(
456     const Config &C, ModuleSummaryIndex &Index,
457     function_ref<bool(GlobalValue::GUID, const GlobalValueSummary *)>
458         isPrevailing,
459     function_ref<void(StringRef, GlobalValue::GUID, GlobalValue::LinkageTypes)>
460         recordNewLinkage,
461     const DenseSet<GlobalValue::GUID> &GUIDPreservedSymbols) {
462   // We won't optimize the globals that are referenced by an alias for now
463   // Ideally we should turn the alias into a global and duplicate the definition
464   // when needed.
465   DenseSet<GlobalValueSummary *> GlobalInvolvedWithAlias;
466   for (auto &I : Index)
467     for (auto &S : I.second.getSummaryList())
468       if (auto AS = dyn_cast<AliasSummary>(S.get()))
469         GlobalInvolvedWithAlias.insert(&AS->getAliasee());
470 
471   for (auto &I : Index)
472     thinLTOResolvePrevailingGUID(C, Index.getValueInfo(I),
473                                  GlobalInvolvedWithAlias, isPrevailing,
474                                  recordNewLinkage, GUIDPreservedSymbols);
475 }
