477 static void thinLTOInternalizeAndPromoteGUID(
478     ValueInfo VI, function_ref<bool(StringRef, ValueInfo)> isExported,
479     function_ref<bool(GlobalValue::GUID, const GlobalValueSummary *)>
480         isPrevailing) {
481   // Before performing index-based internalization and promotion for this GUID,
482   // the local flag should be consistent with the summary list linkage types.
483   VI.verifyLocal();
484 
485   const bool SingleExternallyVisibleCopy =
486       VI.getSummaryList().size() == 1 &&
487       !GlobalValue::isLocalLinkage(VI.getSummaryList().front()->linkage());
488 
489   for (auto &S : VI.getSummaryList()) {
490     // First see if we need to promote an internal value because it is not
491     // exported.
492     if (isExported(S->modulePath(), VI)) {
493       if (GlobalValue::isLocalLinkage(S->linkage()))
494         S->promote();
495       continue;
496     }
497 
498     // Otherwise, see if we can internalize.
499     if (!EnableLTOInternalization)
500       continue;
501 
502     // Non-exported values with external linkage can be internalized.
503     if (GlobalValue::isExternalLinkage(S->linkage())) {
504       S->setLinkage(GlobalValue::InternalLinkage);
505       continue;
506     }
507 
508     // Non-exported function and variable definitions with a weak-for-linker
509     // linkage can be internalized in certain cases. The minimum legality
510     // requirements would be that they are not address taken to ensure that we
511     // don't break pointer equality checks, and that variables are either read-
512     // or write-only. For functions, this is the case if either all copies are
513     // [local_]unnamed_addr, or we can propagate reference edge attributes
514     // (which is how this is guaranteed for variables, when analyzing whether
515     // they are read or write-only).
516     //
517     // However, we only get to this code for weak-for-linkage values in one of
518     // two cases:
519     // 1) The prevailing copy is not in IR (it is in native code).
520     // 2) The prevailing copy in IR is not exported from its module.
521     // Additionally, at least for the new LTO API, case 2 will only happen if
522     // there is exactly one definition of the value (i.e. in exactly one
523     // module), as duplicate defs are result in the value being marked exported.
524     // Likely, users of the legacy LTO API are similar, however, currently there
525     // are llvm-lto based tests of the legacy LTO API that do not mark
526     // duplicate linkonce_odr copies as exported via the tool, so we need
527     // to handle that case below by checking the number of copies.
528     //
529     // Generally, we only want to internalize a weak-for-linker value in case
530     // 2, because in case 1 we cannot see how the value is used to know if it
531     // is read or write-only. We also don't want to bloat the binary with
532     // multiple internalized copies of non-prevailing linkonce/weak functions.
533     // Note if we don't internalize, we will convert non-prevailing copies to
534     // available_externally anyway, so that we drop them after inlining. The
535     // only reason to internalize such a function is if we indeed have a single
536     // copy, because internalizing it won't increase binary size, and enables
537     // use of inliner heuristics that are more aggressive in the face of a
538     // single call to a static (local). For variables, internalizing a read or
539     // write only variable can enable more aggressive optimization. However, we
540     // already perform this elsewhere in the ThinLTO backend handling for
541     // read or write-only variables (processGlobalForThinLTO).
542     //
543     // Therefore, only internalize linkonce/weak if there is a single copy, that
544     // is prevailing in this IR module. We can do so aggressively, without
545     // requiring the address to be insignificant, or that a variable be read or
546     // write-only.
547     if (!GlobalValue::isWeakForLinker(S->linkage()) ||
548         GlobalValue::isExternalWeakLinkage(S->linkage()))
549       continue;
550 
551     // We may have a single summary copy that is externally visible but not
552     // prevailing if the prevailing copy is in a native object.
553     if (SingleExternallyVisibleCopy && isPrevailing(VI.getGUID(), S.get()))
554       S->setLinkage(GlobalValue::InternalLinkage);
555   }
556 }
557 
558 // Update the linkages in the given \p Index to mark exported values
559 // as external and non-exported values as internal.
560 void llvm::thinLTOInternalizeAndPromoteInIndex(
561     ModuleSummaryIndex &Index,
562     function_ref<bool(StringRef, ValueInfo)> isExported,
563     function_ref<bool(GlobalValue::GUID, const GlobalValueSummary *)>
564         isPrevailing) {
565   assert(!Index.withInternalizeAndPromote());
566   for (auto &I : Index)
567     thinLTOInternalizeAndPromoteGUID(Index.getValueInfo(I), isExported,
568                                      isPrevailing);
569   Index.setWithInternalizeAndPromote();
570 }
